import java.util.Base64
import kotlin.math.*
data class BrushPoint(val x:Double,val y:Double);data class DrawingPath(val points:List<BrushPoint>,val d:String,val fontSize:Double);data class Segment(val a:BrushPoint,val b:BrushPoint,val start:Double,val length:Double);data class ArcPath(val points:List<BrushPoint>,val segments:List<Segment>,val totalLength:Double);data class PathSample(val x:Double,val y:Double,val angle:Double,val progress:Double);data class BrushOptions(val fontSize:Double=40.0,val fontFamily:String="Arial, sans-serif",val fontWeight:String="700",val letterSpacing:Double?=null,val color:String="#ffffff",val magicGradient:Boolean=false,val opacity:Double=1.0,val strokeColor:String="rgba(15,23,42,0.72)",val strokeWidth:Double=1.5,val shadow:Boolean=true,val repeatText:Boolean=true,val revealProgress:Double=1.0)
object Brush{
 private fun finite(p:BrushPoint)=p.x.isFinite()&&p.y.isFinite();private fun clamp(v:Double,a:Double,b:Double)=if(v.isFinite())min(b,max(a,v))else a;private fun dist(a:BrushPoint,b:BrushPoint)=hypot(b.x-a.x,b.y-a.y);private fun fmt(v:Double):String{val n=(v*100).roundToInt()/100.0;if(n==0.0)return "0";return "%.2f".format(java.util.Locale.ROOT,n).trimEnd('0').trimEnd('.')};private fun fp(p:BrushPoint)="${fmt(p.x)} ${fmt(p.y)}";private fun along(a:BrushPoint,b:BrushPoint,d:Double):BrushPoint{val l=dist(a,b);if(l==0.0)return a;val t=min(1.0,d/l);return BrushPoint(a.x+(b.x-a.x)*t,a.y+(b.y-a.y)*t)};private fun turn(a:BrushPoint,b:BrushPoint,c:BrushPoint):Double{val ux=b.x-a.x;val uy=b.y-a.y;val vx=c.x-b.x;val vy=c.y-b.y;val ul=hypot(ux,uy);val vl=hypot(vx,vy);return if(ul==0.0||vl==0.0)0.0 else acos(clamp((ux*vx+uy*vy)/(ul*vl),-1.0,1.0))*180/Math.PI}
 fun buildRoundedDrawingPath(input:List<BrushPoint>,fs:Double=40.0):String{val p=input.filter(::finite);if(p.isEmpty())return "";if(p.size==1)return "M ${fp(p[0])}";val out=mutableListOf("M ${fp(p[0])}");val radius=max(12.0,fs*1.25);for(i in 1 until p.size-1){val d=min(radius,min(dist(p[i-1],p[i])*0.45,dist(p[i],p[i+1])*0.45));out+="L ${fp(along(p[i],p[i-1],d))} Q ${fp(p[i])} ${fp(along(p[i],p[i+1],d))}"};out+="L ${fp(p.last())}";return out.joinToString(" ")}
 fun createDrawingPath(p:BrushPoint,fs:Double=40.0)=if(finite(p))DrawingPath(listOf(p),"M ${fp(p)}",fs)else DrawingPath(emptyList(),"",fs);fun appendDrawingPoint(path:DrawingPath,p:BrushPoint):DrawingPath{if(!finite(p)||path.points.isEmpty()||dist(path.points.last(),p)<3)return path;val n=path.points.toMutableList();if(n.size==1||turn(n[n.size-2],n.last(),p)>=18)n+=p else n[n.lastIndex]=p;return DrawingPath(n,buildRoundedDrawingPath(n,path.fontSize),path.fontSize)};private fun drawing(points:List<BrushPoint>,fs:Double):DrawingPath?{var path:DrawingPath?=null;for(p in points.filter(::finite))path=path?.let{appendDrawingPoint(it,p)}?:createDrawingPath(p,fs);return path?.takeIf{it.points.size>=2}}
 private fun perp(p:BrushPoint,a:BrushPoint,b:BrushPoint):Double{val dx=b.x-a.x;val dy=b.y-a.y;val l=dx*dx+dy*dy;if(l==0.0)return dist(p,a);val t=clamp(((p.x-a.x)*dx+(p.y-a.y)*dy)/l,0.0,1.0);return dist(p,BrushPoint(a.x+t*dx,a.y+t*dy))};private fun simplify(p:List<BrushPoint>,tol:Double):List<BrushPoint>{if(p.size<=2)return p;val keep=BooleanArray(p.size);keep[0]=true;keep[p.lastIndex]=true;val stack=java.util.ArrayDeque<Pair<Int,Int>>();stack.push(0 to p.lastIndex);while(stack.isNotEmpty()){val(first,last)=stack.pop();var best=0.0;var index=-1;for(i in first+1 until last){val d=perp(p[i],p[first],p[last]);if(d>best){best=d;index=i}};if(best>tol){keep[index]=true;stack.push(first to index);stack.push(index to last)}};return p.filterIndexed{i,_->keep[i]}}
 fun prepareArcLengthPath(input:List<BrushPoint>,minimum:Double=0.5):ArcPath{val valid=input.filter(::finite);val filtered=mutableListOf<BrushPoint>();for(p in valid)if(filtered.isEmpty()||dist(filtered.last(),p)>=minimum)filtered+=p;if(valid.isNotEmpty()&&filtered.isNotEmpty()&&dist(filtered.last(),valid.last())>0)filtered+=valid.last();val points=simplify(filtered,max(minimum*0.5,0.1));val segments=mutableListOf<Segment>();var total=0.0;for(i in 1 until points.size){val l=dist(points[i-1],points[i]);if(l>0){segments+=Segment(points[i-1],points[i],total,l);total+=l}};return ArcPath(points,segments,total)};private fun pointAt(p:ArcPath,d0:Double):BrushPoint{if(p.segments.isEmpty())return BrushPoint(0.0,0.0);val d=clamp(d0,0.0,p.totalLength);for(s in p.segments)if(d<=s.start+s.length){val t=clamp((d-s.start)/s.length,0.0,1.0);return BrushPoint(s.a.x+(s.b.x-s.a.x)*t,s.a.y+(s.b.y-s.a.y)*t)};return p.segments.last().b};fun sampleAt(p:ArcPath,progress0:Double,fs:Double=40.0):PathSample{val progress=clamp(progress0,0.0,1.0);if(p.totalLength<=0)return PathSample(0.0,0.0,0.0,progress);val d=p.totalLength*progress;val w=max(min(max(fs*1.1,0.75),p.totalLength*0.06),0.75);val a=pointAt(p,d-w);val b=pointAt(p,d+w);val v=pointAt(p,d);return PathSample(v.x,v.y,atan2(b.y-a.y,b.x-a.x),progress)}
 fun stableRepeatedText(text:String,fs:Double):String{val p=text.trim();if(p.isEmpty())return "";val chars=p.codePointCount(0,p.length);val count=ceil(20000/max(fs,chars*fs*0.62)).toInt().coerceIn(16,256);return List(count){p}.joinToString("   ")};private fun esc(v:Any)=v.toString().replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace("\"","&quot;").replace("'","&apos;")
 fun renderSvg(bytes:ByteArray,mime:String,width:Double,height:Double,points:List<BrushPoint>,text:String,o:BrushOptions=BrushOptions()):String{require(mime in listOf("image/png","image/jpeg","image/webp","image/gif","image/avif"));val phrase=text.trim();val fs=if(o.fontSize.isFinite()&&o.fontSize>0)o.fontSize else 40.0;val path=drawing(points,fs);require(phrase.isNotEmpty()&&path!=null);val repeated=if(o.repeatText)stableRepeatedText(phrase,fs)else phrase;val gradient=if(o.magicGradient)"<linearGradient id=\"brush-gradient\" x1=\"100\" y1=\"150\" x2=\"900\" y2=\"850\" gradientUnits=\"userSpaceOnUse\"><stop offset=\"0%\" stop-color=\"#ec4899\"/><stop offset=\"20%\" stop-color=\"#f97316\"/><stop offset=\"40%\" stop-color=\"#facc15\"/><stop offset=\"60%\" stop-color=\"#10b981\"/><stop offset=\"80%\" stop-color=\"#3b82f6\"/><stop offset=\"100%\" stop-color=\"#8b5cf6\"/></linearGradient>"else "";val shadow=if(o.shadow)"<filter id=\"brush-shadow\"><feDropShadow dx=\"0\" dy=\"2\" stdDeviation=\"2\" flood-color=\"#0f172a\" flood-opacity=\"0.65\"/></filter>"else "";val filter=if(o.shadow)" filter=\"url(#brush-shadow)\""else "";val fill=if(o.magicGradient)"url(#brush-gradient)"else esc(o.color);val spacing=o.letterSpacing?:max(0.75,fs*0.06);val reveal=clamp(o.revealProgress,0.0,1.0);val d=esc(path!!.d);return """<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${fmt(width)}" height="${fmt(height)}" viewBox="0 0 ${fmt(width)} ${fmt(height)}"><image width="${fmt(width)}" height="${fmt(height)}" preserveAspectRatio="xMidYMid slice" href="data:$mime;base64,${Base64.getEncoder().encodeToString(bytes)}"/><defs><path id="brush-path" d="$d"/>$gradient$shadow<mask id="brush-reveal"><rect width="100%" height="100%" fill="black"/><path d="$d" pathLength="1" fill="none" stroke="white" stroke-width="${fmt(fs*2.4)}" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="1" stroke-dashoffset="${fmt(1-reveal)}"/></mask></defs><g mask="url(#brush-reveal)" opacity="${fmt(clamp(o.opacity,0.0,1.0))}"$filter><text font-family="${esc(o.fontFamily)}" font-size="${fmt(fs)}" font-weight="${esc(o.fontWeight)}" letter-spacing="${fmt(spacing)}" fill="$fill" stroke="${esc(o.strokeColor)}" stroke-width="${fmt(max(0.0,o.strokeWidth))}" paint-order="stroke fill"><textPath href="#brush-path" xlink:href="#brush-path" startOffset="0" spacing="exact">${esc(repeated)}</textPath></text></g></svg>
"""}
}
